// Brutalist Typographic "Icons" (Non-vibe-coded, system level)
import React from 'react';

const TxtIcon = ({ text, size = 16, className = "", color = "currentColor" }) => (
  <span 
    className={`font-mono font-bold tracking-tighter ${className}`} 
    style={{ fontSize: size, color, lineHeight: 1 }}
  >
    {text}
  </span>
);

export const LayoutDashboard = (p) => <TxtIcon text="[M]" {...p} />;
export const MessageSquare = (p) => <TxtIcon text="[FB]" {...p} />;
export const GitPullRequest = (p) => <TxtIcon text=">-<" {...p} />;
export const Cpu = (p) => <TxtIcon text="<SYS>" {...p} />;
export const RefreshCw = (p) => <TxtIcon text="[R]" {...p} />;
export const Zap = (p) => <TxtIcon text="Z~" {...p} />;
export const BarChart3 = (p) => <TxtIcon text="|||" {...p} />;
export const Clock = (p) => <TxtIcon text="T-" {...p} />;
export const GitMerge = (p) => <TxtIcon text=">~<" {...p} />;
export const AlertTriangle = (p) => <TxtIcon text="/!\\" {...p} />;
export const TrendingUp = (p) => <TxtIcon text="/^/" {...p} />;
export const CheckCircle2 = (p) => <TxtIcon text="[OK]" {...p} />;
export const XCircle = (p) => <TxtIcon text="[ERR]" {...p} />;
export const Loader2 = (p) => <TxtIcon text="..." {...p} />;
export const Twitter = (p) => <TxtIcon text="X://" {...p} />;
export const Github = (p) => <TxtIcon text="GH://" {...p} />;
export const ChevronRight = (p) => <TxtIcon text=">" {...p} />;
export const Play = (p) => <TxtIcon text="|>" {...p} />;
export const Brain = (p) => <TxtIcon text="*AI*" {...p} />;
export const ExternalLink = (p) => <TxtIcon text="->|" {...p} />;
export const Calendar = (p) => <TxtIcon text="[D]" {...p} />;
export const User = (p) => <TxtIcon text="@" {...p} />;
export const Globe = (p) => <TxtIcon text="(W)" {...p} />;
export const Search = (p) => <TxtIcon text="/?" {...p} />;
export const AlertCircle = (p) => <TxtIcon text="(!)" {...p} />;
